    "public static StdKeyDeserializer forType(Class<?> raw)
    {
        int kind;

        // first common types:
        if (raw == String.class || raw == Object.class) {
            return StringKD.forType(raw);
        } else if (raw == UUID.class) {
            kind = TYPE_UUID;
        } else if (raw == Integer.class || raw == Integer.TYPE) {
            kind = TYPE_INT;
        } else if (raw == Long.class || raw == Long.TYPE) {
            kind = TYPE_LONG;
        } else if (raw == Date.class) {
            kind = TYPE_DATE;
        } else if (raw == Calendar.class) {
            kind = TYPE_CALENDAR;
        // then less common ones...
        } else if (raw == Boolean.class || raw == Boolean.TYPE) {
            kind = TYPE_BOOLEAN;
        } else if (raw == Byte.class || raw == Byte.TYPE) {
            kind = TYPE_BYTE;
        } else if (raw == Character.class || raw == Character.TYPE) {
            kind = TYPE_CHAR;
        } else if (raw == Short.class || raw == Short.TYPE) {
            kind = TYPE_SHORT;
        } else if (raw == Float.class || raw == Float.TYPE) {
            kind = TYPE_FLOAT;
        } else if (raw == Double.class || raw == Double.TYPE) {
            kind = TYPE_DOUBLE;
        } else if (raw == URI.class) {
            kind = TYPE_URI;
        } else if (raw == URL.class) {
            kind = TYPE_URL;
        } else if (raw == Class.class) {
            kind = TYPE_CLASS;
        } else if (raw == Locale.class) {
            FromStringDeserializer<?> deser = FromStringDeserializer.findDeserializer(Locale.class);
            return new StdKeyDeserializer(TYPE_LOCALE, raw, deser);
        } else if (raw == Currency.class) {
            FromStringDeserializer<?> deser = FromStringDeserializer.findDeserializer(Currency.class);
            return new StdKeyDeserializer(TYPE_CURRENCY, raw, deser);
        } else {
            return null;
        }
        return new StdKeyDeserializer(kind, raw);
    }"
  ]
}

